sql:
SELECT DISTINCT size_label, category 
FROM sizes 
WHERE standard = 'EU' AND gender = 'Women';

SELECT cf.customer_id, AVG(cf.fit_rating) AS average_fit_rating, AVG(cf.comfort_rating) AS average_comfort_rating
FROM customer_feedback cf
GROUP BY cf.customer_id;

SELECT *
FROM returns_data
WHERE size_id = 0;

SELECT COUNT(*) 
FROM returns_data 
WHERE reason = 'size too small';

SELECT size_id, COUNT(return_id) AS total_returns
FROM returns_data
GROUP BY size_id;

SELECT s.category
FROM sizes s
JOIN (
    SELECT size_id
    FROM size_measurements
    WHERE waist_cm = (
        SELECT MIN(waist_cm)
        FROM size_measurements
    )
) sm ON s.size_id = sm.size_id;

SELECT size_label, category 
FROM sizes 
WHERE size_id <= 1;
